import datetime

app = Flask(__name__)

@app.route('/greet')
def sayHello():
    """
    Pata jina la mtumiaji kutoka kwa ombi,
    angalia kama ni sawa na taratibu zetu,
    halafu rudisha salamu ya asubuhi/mchana/jioni kulingana na saa
    """
    jina = request.args.get('jina', '')
    saa = datetime.datetime.now().hour

    if not jina or not jina.isalpha():
        return "Tafadhali weka jina sahihi, rafiki!"

    if saa < 12:
        return f"Habari ya asubuhi {jina}, umeamkaje?"
    elif saa < 18:
        return f"Mchana mwema {jina}, unaendelea vipi?"
    else:
        return f"Jioni njema {jina}, umepumzika?"

