import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/habari')
def orodheshaHabariZaMtaa():
    '''
    Tunapokea "mtaa" kutoka kwa arguments za request,
    tunaingia kwenye folder ya habari za mtaa huo,
    tunaorodhesha habari zote zinazohusu maendeleo ya jamii,
    halafu tunarudisha orodha kama response.
    '''
    mtaa = request.args.get('mtaa', 'mtaa_wa_kusini')
    try:
        os.chdir(f'/var/www/habari/{mtaa}')
        habari = os.listdir()
        return Response('\n'.join(habari), mimetype='text/plain')
    except Exception as e:
        return Response(f'Hakuna habari kwa sasa: {str(e)}', mimetype='text/plain')

