from flask import Flask, jsonify
app = Flask(__name__)

import traceback

def calculate_harvest_yield(area, crop_type):
    """Kupata kiasi cha mavuno kwa eneo na aina ya zao"""
    try:
        # Kwa mfano, tunatumia formula rahisi ya mavuno
        yield_per_sqm = {
            'mahindi': 0.8,
            'maharage': 0.5,
            'ndizi': 1.2
        }
        return area * yield_per_sqm.get(crop_type, 0.6)
    except Exception as e:
        traceback.print_exc()
        return 0

@app.route('/mavuno')
def server_mavuno():
    """
    Piga hesabu ya mavuno kwa eneo na aina ya zao,
    rudisha majibu kwa mtumiaji kwa njia ya JSON.
    """
    try:
        eneo = 100  # eneo kwa mita za mraba
        zao = 'mahindi'  # aina ya zao
        mavuno = calculate_harvest_yield(eneo, zao)
        return jsonify({
            'eneo': eneo,
            'aina_ya_zao': zao,
            'kiasi_cha_mavuno': mavuno,
            'ujumbe': 'Mavuno yako yatakua nzuri kwa msimu huu!'
        })
    except Exception as e:
        traceback.print_exc()
        return jsonify({'error': 'Kuna tatizo katika hesabu, tafadhali jaribu tena baadaye.'}), 500

