import os, shutil


def arrangeFiles(folderPath):
    '''
    Safely arrange files in the given folderPath by their file types.
    '''
    try:
        for filename in os.listdir(folderPath):
            file_path = os.path.join(folderPath, filename)
            if os.path.isfile(file_path):
                file_ext = os.path.splitext(filename)[1].lower()
                ext_folder = os.path.join(folderPath, file_ext[1:])
                if not os.path.exists(ext_folder):
                    os.makedirs(ext_folder)
                shutil.move(file_path, os.path.join(ext_folder, filename))
        print("Makosa yote imefanikiwa kupangwa vizuri!")
    except Exception as e:
        print(f"Kuna tatizo: {e}")

