@app.route('/chakula', methods=['GET'])
def orodha_chakula():
    return render_template('orodha.html')


def angalia_bei(chakula, bei):
    bei_sahihi = {
        'ugali': 2000,
        'wali': 3000,
        'nyama': 5000,
        'samaki': 4000
    }
    return bei_sahihi.get(chakula.lower(), 0) == bei


@app.route('/agiza', methods=['POST'])
def fanya_agizo():
    '''
    Pata jina la chakula na bei kutoka kwa ombi la mtumiaji.
    Angalia kama bei ni sahihi kwa kuitumia funguo za bei katika angalia_bei().
    Kama bei ni sahihi, tengeneza ombi jipya na uhifadhi taarifa za ombi katika kuki.
    '''
    chakula = request.form.get('chakula')
    bei = int(request.form.get('bei', 0))

    if angalia_bei(chakula, bei):
        response = make_response(render_template('agizo_limekubaliwa.html'))
        response.set_cookie('agizo_id', secrets.token_hex(16))
        return response
    else:
        return render_template('bei_sio_sahihi.html')

