import socket


def tengeneza_kiungo_cha_tovuti(url):
    '''
    Tengeneza kiungo cha mtandao kwa kutumia socket ya IPv4 na TCP ili kupata habari kutoka kwa tovuti iliyotajwa.
    Rudisha taarifa za mafanikio au kushindwa kwa muunganisho.
    '''
    try:
        # Tengeneza socket ya IPv4 na TCP
        soketi = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        # Pata anwani ya IP ya tovuti
        anwani = socket.gethostbyname(url)
        # Unganisha kwa port 80 (HTTP)
        soketi.connect((anwani, 80))
        return {"status": "mafanikio", "message": "Umeunganishwa na tovuti '" + url + "' kwa mafanikio"}
    except Exception as e:
        return {"status": "kushindwa", "message": "Hitilafu: " + str(e)}

