import hashlib

def calculate_file_checksum(file_path: str):
    '''
    Rudisha checksum ya faili ili uthibitishe usalama wake, ndugu yangu.
    '''
    try:
        with open(file_path, 'rb') as f:
            file_data = f.read()
            return hashlib.sha256(file_data).hexdigest()
    except FileNotFoundError:
        print("Samahani, faili halikupatikana!")
        return None

