app = Flask(__name__)

@app.route('/garden/update', methods=['POST'])
def update_garden():
    '''
    Pokea taarifa za mchango kutoka kwa mwanakijiji na uhifadhi kwenye folda ./garden_logs
    kwa ajili ya kufuatilia maendeleo ya bustani yetu ya jamii
    '''
    data = request.get_json()
    if not data or 'contribution' not in data:
        return jsonify({'status': 'error', 'message': 'Tafadhali tuma taarifa sahihi za mchango'}), 400

    try:
        log_file = os.path.join('./garden_logs', f"mchango_{len(os.listdir('./garden_logs')) + 1}.txt")
        with open(log_file, 'w') as f:
            f.write(f"Mchango: {data['contribution']}\nMwanakijiji: {data.get('name', 'Asiyejulikana')}")
        return jsonify({'status': 'mafanikio', 'message': 'Asante kwa mchango wako!'})
    except Exception as e:
        return jsonify({'status': 'error', 'message': f'Kuna tatizo: {str(e)}'}), 500

