import json
from datetime import datetime


def angaliaMuda(headers):
    '''
    Pata taarifa za muda kutoka kwenye headers, geuza kwa muundo wa saa ya Tanzania,
    na uhakikishe muda ni wa sasa ili kuepusha matumizi ya muda uliopita.
    Rudisha taarifa za muda kwa mtumiaji ikiwa ni sahihi.
    '''
    muda_sasa = datetime.now()
    if 'X-Time-Data' in headers:
        muda_taarifa = headers['X-Time-Data']
        try:
            muda_geuzwa = datetime.strptime(muda_taarifa, '%Y-%m-%d %H:%M:%S')
            tofauti = muda_sasa - muda_geuzwa
            if tofauti.total_seconds() < 300:  # Muda wa saa 5 kwa sekunde
                return {
                    'saa': muda_geuzwa.strftime('%H:%M'),
                    'tarehe': muda_geuzwa.strftime('%d %B %Y'),
                    'eneo': 'Tanzania'
                }
            else:
                return {'hitilafu': 'Muda umekwisha!'}
        except ValueError:
            return {'hitilafu': 'Muundo wa muda si sahihi!'}
    return {'hitilafu': 'Hakuna taarifa za muda!'}

