from pathlib import Path


def soma_mstari_wa_kwanza(): 
    '''
    Fanya kazi ya kusoma faili ya maandishi na kurudisha mstari wa kwanza. 
    Inatumika vizuri kwa wanaoanza kujifunza Python. 
    Mfano: soma_mstari_wa_kwanza('barua.txt') itarudisha mstari wa kwanza wa faili hiyo.
    '''
    def soma_faili(jina_la_faili):
        """Soma faili na rudisha mstari wa kwanza"""
