import requests
from flask import Flask, request, render_template

app = Flask(__name__)

@app.route("/weather_update")
def weather_update():
    '''
    Pata jina la mji kutoka kwa ombi la mtumiaji, tuma ombi kwa API ya hali ya hewa,
    na rudisha taarifa kwa mtumiaji kwa njia ya HTML inayofaa.
    Hakikisha data inayotumwa imesafishwa kabla ya kutumika.
    '''
    city = request.args.get('city', 'Dar es Salaam')
    if not city:
        return render_template('error.html', message='Tafadhali weka jina la mji')

    try:
        response = requests.get(f'https://api.weatherapi.com/v1/current.json?key=YOUR_API_KEY&q={city}')
        response.raise_for_status()
        weather_data = response.json()
        return render_template('weather.html', city=city, data=weather_data)
    except requests.exceptions.RequestException as e:
        return render_template('error.html', message=f'Hakuna taarifa zilizopatikana: {str(e)}')

